39	                                                                           enable_custom_all_reduce_);
40	
41	    bool use_gated_activation = activation_type_ == ActivationType::GeGLU || activation_type_ == ActivationType::ReGLU;
42	    size_t max_inter_size     = has_adapters_ ? std::max(inter_size_, adapter_inter_size_) : inter_size_;
43	    if (activation_type_ == ActivationType::Gelu || activation_type_ == ActivationType::GeGLU) {
