159	template<typename T>
160	void ParallelGptDecoder<T>::allocateBuffer()
161	{
162	    FT_CHECK(false);
163	}
164	
165	template<typename T>
166	void ParallelGptDecoder<T>::allocateBuffer(size_t batch_size)
167	{
168	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
169	    decoder_layer_output_ = reinterpret_cast<T*>(
170	        allocator_->reMalloc(decoder_layer_output_, sizeof(T) * batch_size * hidden_units_, false));
171	    decoder_normed_input_ = reinterpret_cast<T*>(
172	        allocator_->reMalloc(decoder_normed_input_, sizeof(T) * batch_size * hidden_units_, false));
173	    self_attn_output_ =
174	        reinterpret_cast<T*>(allocator_->reMalloc(self_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
175	    normed_self_attn_output_ = reinterpret_cast<T*>(
176	        allocator_->reMalloc(normed_self_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
177	    // only allocate additionl buffers when has adapters
178	    after_adapter_attn_output_ = has_adapters_ ? reinterpret_cast<T*>(allocator_->reMalloc(
179	                                     after_adapter_attn_output_, sizeof(T) * batch_size * hidden_units_, false)) :
180	                                                 self_attn_output_;
181	    // for moe
182	    expert_scales_ = reinterpret_cast<T*>(
183	        allocator_->reMalloc(expert_scales_, sizeof(T) * pad_to_multiple_of_16(moe_k_ * batch_size), false));
184	    expanded_source_row_to_expanded_dest_row_ = reinterpret_cast<int*>(allocator_->reMalloc(
185	        expanded_source_row_to_expanded_dest_row_, sizeof(int) * pad_to_multiple_of_16(moe_k_ * batch_size), false));
186	    expert_for_source_row_                    = reinterpret_cast<int*>(
187	        allocator_->reMalloc(expert_for_source_row_, sizeof(int) * pad_to_multiple_of_16(moe_k_ * batch_size), false));
188	    fc2_result_ = reinterpret_cast<T*>(allocator_->reMalloc(
189	        fc2_result_, sizeof(T) * pad_to_multiple_of_16(moe_k_ * batch_size * hidden_units_), false));
190	    adapter_fc2_result_ =
191	        has_adapters_ ? reinterpret_cast<T*>(allocator_->reMalloc(
192	            adapter_fc2_result_, sizeof(T) * pad_to_multiple_of_16(moe_k_ * batch_size * hidden_units_), false)) :
193	                        nullptr;
194	    is_allocate_buffer_ = true;
195	}
196	
197	template<typename T>
198	void ParallelGptDecoder<T>::freeBuffer()
199	{
200	    if (is_allocate_buffer_) {
201	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
202	        allocator_->free((void**)(&decoder_layer_output_));
203	        allocator_->free((void**)(&decoder_normed_input_));
204	        allocator_->free((void**)(&self_attn_output_));
205	        allocator_->free((void**)(&normed_self_attn_output_));
206	        if (has_adapters_) {
207	            allocator_->free((void**)(&after_adapter_attn_output_));
208	            allocator_->free((void**)(&adapter_fc2_result_));
209	        }
210	        is_allocate_buffer_ = false;
211	
212	        allocator_->free((void**)(&expert_scales_));
213	        allocator_->free((void**)(&expanded_source_row_to_expanded_dest_row_));
214	        allocator_->free((void**)(&expert_for_source_row_));
215	        allocator_->free((void**)(&fc2_result_));
216	    }
217	}
