30	// PROMPT_SRC: 0 --> no prompts, 1 --> from loaded prompts, 2 --> from request prompts
31	template<typename T, bool OUTPUT_ID, int PROMPT_SRC>
32	__global__ void start_id_embedding_position_lookups_kernel(T*                    from_tensor,
33	                                                           int*                  output_ids,
34	                                                           const T*              embedding_table,
35	                                                           const T*              pos_table,
36	                                                           pPromptTuningParam<T> prompt_param,
37	                                                           const int*            input_ids,
38	                                                           const int             start_step,
39	                                                           const int             length,
40	                                                           const int             max_length,
41	                                                           const int             batch_size,
42	                                                           const int64_t         hidden_units)
43	{
44	    for (int index = blockIdx.x * blockDim.x + threadIdx.x; index < batch_size * length * hidden_units;
45	         index += blockDim.x * gridDim.x) {
46	        // transpose the input_ids [batch, length] (part of [batch, max_length]) to output_ids [length, batch]
47	        if (OUTPUT_ID && index < batch_size * max_length) {
48	            // for p/prompt_tuning (have prompt templates like [input1, prompt1, input2, prompt2])
49	            // we have to process it to like [input1, input2, prompt1, prompt2], and then remove the prompts during post
50	            // processing
51	            if (PROMPT_SRC > 0) {
52	                if (index < batch_size) {
53	                    int no_prompt_output_seq_id = 0;
54	#pragma unroll 1
55	                    for (int seq_id = 0; seq_id < max_length; seq_id++) {
56	                        int current_input_id = input_ids[index * max_length + seq_id];
57	                        if (current_input_id < prompt_param.p_prompt_tuning_id_start) {
58	                            output_ids[no_prompt_output_seq_id * batch_size + index] = current_input_id;
59	                            no_prompt_output_seq_id++;
60	                        }
61	                    }
62	                }
63	            }
64	            else {
65	                const int seq_id   = index % max_length;
66	                const int batch_id = index / max_length;
67	                if (seq_id < length) {
68	                    output_ids[seq_id * batch_size + batch_id] = input_ids[index];
69	                }
70	            }
71	        }
72	
73	        // embedding lookup from word ids [batch, length] (part of [batch, max_length]) and [vocab, hidden] to generate
74	        // embedding [batch, length, hidden]
75	        const int word_index      = index / hidden_units;
76	        const int word_index_row  = word_index / length;  // batch_id
77	        const int word_index_col  = word_index % length;
78	        const int real_word_index = word_index_row * max_length + word_index_col;
79	        const int step            = start_step + word_index % length;
80	        const int col_index       = index % hidden_units;
81	        const int input_id        = input_ids == nullptr ? real_word_index : input_ids[real_word_index];
82	        const int prompt_id       = input_id - prompt_param.p_prompt_tuning_id_start;
83	        T         embedding       = (T)0.0f;
84	        if (PROMPT_SRC > 0 && prompt_id >= 0) {
85	            if (PROMPT_SRC == 1) {
86	                // from loaded prompt embedding tables
87	                embedding =
88	                    prompt_param.p_prompt_tuning_batch_weights[word_index_row][prompt_id * hidden_units + col_index];
89	            }
90	            else {
91	                // from request prompt embedding
92	                embedding =
93	                    prompt_param
94	                        .request_prompt_embedding[word_index_row * prompt_param.request_prompt_max_length * hidden_units
95	                                                  + prompt_id * hidden_units + col_index];
96	            }
97	        }
98	        else {
99	            embedding = embedding_table[input_id * hidden_units + col_index];
100	        }
101	        T pos_embed        = pos_table == nullptr ? (T)0.f : pos_table[(step - 1) * hidden_units + col_index];
102	        from_tensor[index] = embedding + pos_embed;
103	    }
104	}
105	
106	#define WORD_POS_EMBEDDING_LOOPUP_KERNEL(OUTPUT_ID, PROMPT_SRC)                                                        \
107	    start_id_embedding_position_lookups_kernel<T, OUTPUT_ID, PROMPT_SRC><<<grid, block, 0, stream>>>(from_tensor,      \
108	                                                                                                     output_ids,       \
109	                                                                                                     embedding_table,  \
