203	template<typename T>
204	__global__ void inputIdsEmbeddingLookupPosEncodingSoftPrompt(inputIdsEmbeddingLookupPosEncodingSoftPromptParam<T> param)
205	{
206	    // 1. Copy the input ids to output ids and transpose output ids to [seq_len, batch_size, beam_width].
207	    // 2. Embedding lookup by input ids and concat with soft prompt. The axis of concatenation is on axis of seq_len.
208	
209	    // Assume batch size is 2 and prompts are [[t1, t2], [t3], [t4, t5]], input_ids are [[s1, s2], [s3], [s4]]
210	    // then the order of output_ids is
211	    // [ [?, ?, s1, s2]
212	    //   [?, s3, padding, padding]
213	    //   [?, ?, s4, padding] ]
214	    // and the order of embedding is
215	    // [ [t1, t2, s1, s2]
216	    //   [t3, s3, padding, padding]
217	    //   [t4, t5, s4, padding] ]
218	    // where "?" means undefined values and we should attach it.
219	
220	    for (int index = blockIdx.x * blockDim.x + threadIdx.x;
221	         index < param.batch_size * param.beam_width * (param.max_prefix_soft_prompt_length + param.max_input_length)
222	                     * param.hidden_units;
223	         index += blockDim.x * gridDim.x) {
224	        // transpose the input_ids [batch, length] (part of [batch, beam, max_input_length]) to
225	        // output_ids [length, batch, beam].
226	        // ouptut_ids need to add padding in the beginning for soft prompting.
227	
228	        if (index < param.batch_size * param.beam_width * param.max_input_length) {
229	            int       tmp_index = index;
230	            const int seq_id    = tmp_index % param.max_input_length;
231	            tmp_index           = (tmp_index - seq_id) / param.max_input_length;
232	            const int beam_id   = tmp_index % param.beam_width;
233	            tmp_index           = (tmp_index - beam_id) / param.beam_width;
234	            const int batch_id  = tmp_index % param.batch_size;
235	            if (seq_id < param.max_input_length) {
236	                param.output_ids[(param.prefix_soft_prompt_lengths[batch_id] + seq_id) * param.batch_size
237	                                     * param.beam_width
238	                                 + batch_id * param.beam_width + beam_id] = param.input_ids[index];
239	            }
240	        }
241	
242	        // embedding lookup from word ids [batch, beam, length] (part of [batch, beam, max_input_length]), [vocab,
243	        // hidden] and [batch, max_prefix_soft_prompt_length, hidden] to generate embedding [batch, beam, length +
244	        // max_prefix_soft_prompt_length, hidden]
245	        int       tmp_index = index;
246	        const int hidden_id = tmp_index % param.hidden_units;
247	        tmp_index           = (tmp_index - hidden_id) / param.hidden_units;
248	        const int seq_id    = tmp_index % (param.max_prefix_soft_prompt_length + param.max_input_length);
249	        tmp_index           = (tmp_index - seq_id) / (param.max_prefix_soft_prompt_length + param.max_input_length);
250	        const int beam_id   = tmp_index % param.beam_width;
251	        tmp_index           = (tmp_index - beam_id) / param.beam_width;
252	        const int batch_id  = tmp_index % param.batch_size;
253	        const int64_t hidden_units = param.hidden_units;
254	        T         embedding =
255	            (seq_id < param.prefix_soft_prompt_lengths[batch_id]) ?
256	                        (T)param.prefix_soft_prompt_embedding[batch_id * param.max_prefix_soft_prompt_length * hidden_units
257	                                                      + seq_id * hidden_units + hidden_id] :
258	                            param.embedding_table[param.input_ids[batch_id * param.beam_width * param.max_input_length
259	                                                      + beam_id * param.max_input_length
260	                                                      + (seq_id - param.prefix_soft_prompt_lengths[batch_id])]
261	                                          * hidden_units
262	                                      + hidden_id];
263	
264	        T pos_embed              = param.pos_table == nullptr ?
265	                                       (T)0.0f :
266	                                       param.pos_table[(param.start_step + seq_id - 1) * hidden_units + hidden_id];
267	        param.from_tensor[index] = embedding + pos_embed;
268	
269	        if (seq_id == 0 && hidden_id == 0) {
270	            param.input_lengths[batch_id * param.beam_width + beam_id] += param.prefix_soft_prompt_lengths[batch_id];
271	        }
272	    }
273	}
