438	__launch_bounds__(1024, 1) __global__ void lookupHiddenStateOfLastToken(T*         from_tensor,
439	                                                                        const T*   hidden_state,
440	                                                                        const int* input_lengths,
441	                                                                        const int  max_input_length,
442	                                                                        const int  batch_size,
443	                                                                        const int  hidden_units)
444	{
445	    for (int index = blockIdx.x * blockDim.x + threadIdx.x; index < batch_size * hidden_units;
