447	        const int col_index = index % hidden_units;
448	        const int batch_id  = index / hidden_units;
449	        from_tensor[index]  = hidden_state[batch_id * max_input_length * hidden_units
450	                                          + (input_lengths[batch_id] - 1) * hidden_units + col_index];
451	    }
452	}
