704	void invokeFindContextDups(int*         shared_contexts,
705	                           int*         batch_to_compact,
706	                           int*         compact_to_batch,
707	                           int*         compact_size,
708	                           const int*   input_ids,
709	                           const size_t batch_size,
710	                           const size_t beam_width,
711	                           const size_t input_seq_len,
712	                           cudaStream_t stream)
713	{
714	    dim3 block{512};
715	    dim3 grid{((int)batch_size + block.x - 1) / block.x};
716	    // set shared_context[i] = i
717	    init_shared_contexts<<<grid, block, 0, stream>>>(shared_contexts, batch_size);
718	
719	    grid = dim3{(unsigned int)(batch_size * (batch_size - 1)) / 2};
720	    // set shared_contexts[i] = j, where j = min{k, such that input_ids[k] == input_ids[i]}
721	    if (input_seq_len <= 128) {
722	        block = 128;
723	        find_context_dups<128><<<grid, block, 0, stream>>>(shared_contexts, input_ids, batch_size, input_seq_len);
724	    }
725	    else {
726	        block = 256;
727	        find_context_dups<256><<<grid, block, 0, stream>>>(shared_contexts, input_ids, batch_size, input_seq_len);
728	    }
729	
730	    // set batch_to_compact[i] = j, where j is the position of input_ids[i] in the compact_batch
731	    // set compact_to_batch[i] = j, where j is such that compact_to_batch[i] = input_ids[j]
732	    generate_dups_indices<<<1, DUPS_INDICES_BLOCK_SIZE, 0, stream>>>(
733	        batch_to_compact, compact_to_batch, compact_size, shared_contexts, batch_size, beam_width, input_seq_len);
734	}
