981	template<bool PREFIX_PROMPT>
982	__global__ void update_padding_count(int*       total_padding_count,
983	                                     const int* input_lengths,
984	                                     const int* tiled_prompt_lengths,
985	                                     size_t     max_input_length,
986	                                     size_t     max_prompt_length,
987	                                     size_t     batch_size,
988	                                     size_t     beam_width)
989	{
990	    const int gidx = blockIdx.x * blockDim.x + threadIdx.x;
991	
992	    if (gidx >= batch_size * beam_width) {
993	        return;
994	    }
995	
996	    const int batch_idx = gidx / beam_width;
997	
998	    total_padding_count[gidx] +=
999	        PREFIX_PROMPT ? (max_input_length + max_prompt_length - input_lengths[batch_idx] - tiled_prompt_lengths[gidx]) :
1000	                        (max_input_length - input_lengths[batch_idx]);
1001	}
