1085	__global__ void sum_length_dimension(
1086	    float* out_buf, const T* in_buf, const size_t batch_size, const size_t input_length, const size_t hidden_dim)
1087	{
1088	    const int bidx = blockIdx.x;
1089	
1090	    for (int hidx = threadIdx.x; hidx < hidden_dim; hidx += blockDim.x) {
1091	        float accum = 0.0f;
1092	        for (int step = 0; step < input_length; step++) {
1093	            accum += static_cast<float>(in_buf[(bidx * input_length + step) * hidden_dim + hidx]);
1094	        }
1095	        out_buf[bidx * hidden_dim + hidx] = accum;
1096	    }
1097	}
