95	template<typename T>
96	void ParallelGpt<T>::allocateBuffer(size_t batch_size,
97	                                    size_t beam_width,
98	                                    size_t max_session_len,
99	                                    size_t memory_len,
100	                                    size_t max_input_len,
101	                                    bool   is_return_context_cum_log_probs)
102	{
103	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
104	    const size_t batchxbeam       = batch_size * beam_width;
105	    const size_t local_batch_size = getLocalBatchSize(batch_size, 1, pipeline_para_.world_size_);
106	    FT_CHECK(batch_size % local_batch_size == 0);
107	    const size_t num_microbatches = batch_size / local_batch_size;
108	
109	    const size_t self_cache_size =
110	        (num_layer_ / pipeline_para_.world_size_) * batchxbeam * memory_len * hidden_units_ / tensor_para_.world_size_;
111	
112	    if (vocab_size_ != vocab_size_padded_) {
113	        padded_embedding_kernel_ =
114	            (T*)(allocator_->reMalloc(padded_embedding_kernel_, sizeof(T) * hidden_units_ * vocab_size_padded_, true));
115	        padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
116	    }
117	
118	    tiled_input_attention_mask_ = (T*)(allocator_->reMalloc(
119	        tiled_input_attention_mask_, sizeof(T) * batchxbeam * max_input_len * max_input_len, false));
120	    decoder_input_buf_ = (T*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
121	    decoder_normed_input_buf_ =
122	        (T*)(allocator_->reMalloc(decoder_normed_input_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
123	    decoder_output_buf_ =
124	        (T*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
125	    normed_decoder_output_buf_ =
126	        (T*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
127	    logits_buf_ = (float*)(allocator_->reMalloc(logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
128	    nccl_logits_buf_ =
129	        (float*)(allocator_->reMalloc(nccl_logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
130	    cum_log_probs_    = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
131	    finished_buf_     = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
132	    sequence_lengths_ = (int*)(allocator_->reMalloc(sequence_lengths_, sizeof(int) * batchxbeam, false));
133	
134	    key_cache_   = (T*)(allocator_->reMalloc(key_cache_, sizeof(T) * self_cache_size * 2, true));
135	    value_cache_ = key_cache_ + self_cache_size;
136	    if (beam_width > 1) {
137	        cache_indirections_[0] =
138	            (int*)(allocator_->reMalloc(cache_indirections_[0], sizeof(int) * batchxbeam * memory_len * 2, true));
139	        cache_indirections_[1] = cache_indirections_[0] + batchxbeam * memory_len;
140	    }
141	
142	    tiled_input_ids_buf_ =
143	        (int*)(allocator_->reMalloc(tiled_input_ids_buf_, sizeof(int) * batchxbeam * max_session_len, true));
144	    tiled_input_lengths_buf_ = (int*)(allocator_->reMalloc(tiled_input_lengths_buf_, sizeof(int) * batchxbeam, true));
145	
146	    // prompt_learning weight batch ptrs
147	    prompt_learning_weight_batch_ =
148	        (const T**)(allocator_->reMalloc(prompt_learning_weight_batch_, sizeof(T*) * batchxbeam, false));
149	    tiled_prompt_lengths_buf_ =
150	        (int*)(allocator_->reMalloc(tiled_prompt_lengths_buf_, sizeof(int) * batchxbeam, false));
151	
152	    start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * batch_size, false));
153	    end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * batch_size, false));
154	
155	    transposed_output_ids_buf_ =
156	        (int*)(allocator_->reMalloc(transposed_output_ids_buf_, sizeof(int) * batchxbeam * max_session_len, true));
157	    output_ids_buf_ = (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * max_session_len, true));
158	    parent_ids_buf_ = (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * max_session_len, true));
159	    seq_limit_len_  = (uint32_t*)(allocator_->reMalloc(seq_limit_len_, sizeof(uint32_t) * batch_size, false));
160	    tiled_masked_tokens_ =
161	        (bool*)(allocator_->reMalloc(tiled_masked_tokens_, sizeof(bool) * batchxbeam * memory_len, true));
162	
163	    context_decoder_input_buf_  = (T*)(allocator_->reMalloc(
164	        context_decoder_input_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false));
165	    context_decoder_output_buf_ = (T*)(allocator_->reMalloc(
166	        context_decoder_output_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false));
167	    output_log_probs_buf_ =
168	        (float*)(allocator_->reMalloc(output_log_probs_buf_, sizeof(float) * batchxbeam * max_session_len, false));
169	
170	    if (gpt_variant_params_.has_pre_decoder_layernorm) {
171	        context_decoder_normed_input_buf_ = (T*)allocator_->reMalloc(
172	            context_decoder_normed_input_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false);
173	        decoder_normed_input_buf_ =
174	            (T*)allocator_->reMalloc(decoder_normed_input_buf_, sizeof(T) * batchxbeam * hidden_units_, false);
175	    }
176	
177	    if (gpt_variant_params_.use_attention_linear_bias) {
178	        linear_bias_slopes_ = (T*)(allocator_->reMalloc(linear_bias_slopes_, sizeof(T) * head_num_, false));
179	    }
180	
181	    if (is_return_context_cum_log_probs) {
182	        lp_normed_decoder_output_buf_ = (T*)allocator_->reMalloc(
183	            lp_normed_decoder_output_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_);
184	        lp_logits_buf_      = (float*)allocator_->reMalloc(lp_logits_buf_,
185	                                                      sizeof(float) * batchxbeam * max_input_len * vocab_size_padded_);
186	        lp_nccl_logits_buf_ = (float*)allocator_->reMalloc(
187	            lp_nccl_logits_buf_, sizeof(float) * batchxbeam * max_input_len * vocab_size_padded_);
188	        lp_logprob_buf_ = (float*)allocator_->reMalloc(lp_logprob_buf_, sizeof(float) * batchxbeam * max_input_len);
189	    }
190	    if (shared_contexts_ratio_ > 0.0f) {
191	        shared_contexts_idx_  = (int*)allocator_->reMalloc(shared_contexts_idx_, batch_size * sizeof(int), false);
192	        batch_to_compact_idx_ = (int*)allocator_->reMalloc(batch_to_compact_idx_, batchxbeam * sizeof(int), false);
193	        compact_idx_          = (int*)allocator_->reMalloc(compact_idx_, batch_size * sizeof(int), false);
194	        compact_size_         = (int*)allocator_->reMalloc(compact_size_, sizeof(int), false);
195	    }
196	    microbatch_should_stop_ =
197	        (bool*)allocator_->reMalloc(microbatch_should_stop_, sizeof(bool) * num_microbatches, true, true);
198	    tiled_total_padding_count_ =
199	        (int*)allocator_->reMalloc(tiled_total_padding_count_, batchxbeam * sizeof(int), false);
200	
201	    is_allocate_buffer_ = true;
202	}
