204	template<typename T>
205	void ParallelGpt<T>::freeBuffer()
206	{
207	    if (is_allocate_buffer_) {
208	        if (vocab_size_ != vocab_size_padded_) {
209	            padded_embedding_kernel_ptr_ = nullptr;
210	            allocator_->free((void**)(&padded_embedding_kernel_));
211	        }
212	
213	        allocator_->free((void**)(&tiled_input_attention_mask_));
214	        allocator_->free((void**)(&decoder_input_buf_));
215	        allocator_->free((void**)(&decoder_output_buf_));
216	        allocator_->free((void**)(&normed_decoder_output_buf_));
217	        allocator_->free((void**)(&logits_buf_));
218	        allocator_->free((void**)(&nccl_logits_buf_));
219	        allocator_->free((void**)(&cum_log_probs_));
220	        allocator_->free((void**)(&finished_buf_));
221	        allocator_->free((void**)(&sequence_lengths_));
222	
223	        allocator_->free((void**)(&key_cache_));
224	        if (cache_indirections_[0] != nullptr) {
225	            allocator_->free((void**)(&cache_indirections_)[0]);
226	        }
227	
228	        allocator_->free((void**)(&tiled_input_ids_buf_));
229	        allocator_->free((void**)(&tiled_input_lengths_buf_));
230	
231	        allocator_->free((void**)(&prompt_learning_weight_batch_));
232	        allocator_->free((void**)(&tiled_prompt_lengths_buf_));
233	
234	        allocator_->free((void**)(&transposed_output_ids_buf_));
235	        allocator_->free((void**)(&output_ids_buf_));
236	        allocator_->free((void**)(&parent_ids_buf_));
237	        allocator_->free((void**)(&tiled_masked_tokens_));
238	
239	        allocator_->free((void**)(&seq_limit_len_));
240	
241	        allocator_->free((void**)(&start_ids_buf_));
242	        allocator_->free((void**)(&end_ids_buf_));
243	
244	        allocator_->free((void**)(&context_decoder_input_buf_));
245	        allocator_->free((void**)(&context_decoder_output_buf_));
246	        allocator_->free((void**)(&output_log_probs_buf_));
247	
248	        if (gpt_variant_params_.has_pre_decoder_layernorm) {
249	            allocator_->free((void**)(&context_decoder_normed_input_buf_));
250	            allocator_->free((void**)(&decoder_normed_input_buf_));
251	        }
252	        if (gpt_variant_params_.use_attention_linear_bias) {
253	            allocator_->free((void**)(&linear_bias_slopes_));
254	        }
255	
256	        allocator_->free((void**)(&lp_normed_decoder_output_buf_));
257	        allocator_->free((void**)(&lp_logits_buf_));
258	        allocator_->free((void**)(&lp_nccl_logits_buf_));
259	        allocator_->free((void**)(&lp_logprob_buf_));
260	
261	        allocator_->free((void**)(&microbatch_should_stop_), true);
262	
263	        if (shared_contexts_ratio_ > 0.0f) {
264	            allocator_->free((void**)(&shared_contexts_idx_));
265	            allocator_->free((void**)(&compact_size_));
266	        }
267	        allocator_->free((void**)(&tiled_total_padding_count_));
268	
269	        is_allocate_buffer_ = false;
270	    }
271	}
