402	template<typename T>
403	void ParallelGpt<T>::computeContextCumLogProbs(float*                      cum_log_probs,
404	                                               const T*                    context_decoder_outputs,
405	                                               const int*                  input_ids,
406	                                               const int*                  input_lengths,
407	                                               const size_t                batch_size,
408	                                               const size_t                beam_width,
409	                                               const size_t                max_input_length,
410	                                               const ParallelGptWeight<T>* gpt_weights)
411	{
412	    // Compute the log probabilties of prompt inputs.
413	    //
414	    // cum_log_probs [batch_size, beam_width]
415	    // context_decoder_outputs [batch_size * beam_width, max_input_length, hidden_units]
416	    // input_ids [batch_size * beam_width, max_input_length]; input ids.
417	    // input_lengths [batch_size, beam_width]; input lengths.
418	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
419	
420	    const size_t batchxbeam      = batch_size * beam_width;
421	    const size_t n_hidden_states = batchxbeam * max_input_length;
422	
423	    const cudaDataType_t cublas_type = getCudaDataType<T>();
424	
425	    if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
426	        // normed decoder output [batch_size * beam_width, max_input_length, hidden_units_]
427	        invokeGeneralLayerNorm(lp_normed_decoder_output_buf_,
428	                               context_decoder_outputs,
429	                               gpt_weights->post_decoder_layernorm.gamma,
430	                               gpt_weights->post_decoder_layernorm.beta,
431	                               layernorm_eps_,
432	                               n_hidden_states,
433	                               hidden_units_,
434	                               (float*)nullptr,
435	                               0,
436	                               stream_);
437	        sync_check_cuda_error();
438	        if (tensor_para_.world_size_ == 1) {
439	            float alpha = 1.0f;
440	            float beta  = 0.0f;
441	            cublas_wrapper_->Gemm(CUBLAS_OP_T,
442	                                  CUBLAS_OP_N,
443	                                  vocab_size_padded_,  // n
444	                                  n_hidden_states,
445	                                  hidden_units_,  // k
446	                                  &alpha,
447	                                  padded_embedding_kernel_ptr_,
448	                                  cublas_type,
449	                                  hidden_units_,  // k
450	                                  lp_normed_decoder_output_buf_,
451	                                  cublas_type,
452	                                  hidden_units_,  // k
453	                                  &beta,
454	                                  lp_logits_buf_,
455	                                  CUDA_R_32F,
456	                                  vocab_size_padded_, /* n */
457	                                  CUDA_R_32F,
458	                                  cublasGemmAlgo_t(-1));
459	            sync_check_cuda_error();
460	        }
461	        else {
462	            FT_CHECK(vocab_size_padded_ % tensor_para_.world_size_ == 0);
463	            const int local_vocab_size = vocab_size_padded_ / tensor_para_.world_size_;
464	            float     alpha            = 1.0f;
465	            float     beta             = 0.0f;
466	            cublas_wrapper_->Gemm(CUBLAS_OP_T,
467	                                  CUBLAS_OP_N,
468	                                  local_vocab_size,  // n
469	                                  n_hidden_states,
470	                                  hidden_units_,  // k
471	                                  &alpha,
472	                                  padded_embedding_kernel_ptr_ + tensor_para_.rank_ * local_vocab_size * hidden_units_,
473	                                  cublas_type,
474	                                  hidden_units_,  // k
475	                                  lp_normed_decoder_output_buf_,
476	                                  cublas_type,
477	                                  hidden_units_,  // k
478	                                  &beta,
479	                                  lp_nccl_logits_buf_ + tensor_para_.rank_ * n_hidden_states * local_vocab_size,
480	                                  CUDA_R_32F,
481	                                  local_vocab_size, /* n */
482	                                  CUDA_R_32F,
483	                                  cublasGemmAlgo_t(-1));
484	            sync_check_cuda_error();
485	            ftNcclAllGather(lp_nccl_logits_buf_,
486	                            lp_nccl_logits_buf_,
487	                            n_hidden_states * local_vocab_size,
488	                            tensor_para_.rank_,
489	                            tensor_para_,
490	                            stream_);
491	            check_cuda_error(cudaStreamSynchronize(stream_));
492	            sync_check_cuda_error();
493	
494	            invokeTransposeAxis01(lp_logits_buf_,
495	                                  lp_nccl_logits_buf_,
496	                                  tensor_para_.world_size_,
497	                                  n_hidden_states,
498	                                  local_vocab_size,
499	                                  stream_);
500	            sync_check_cuda_error();
501	        }
502	    }
503	
504	    invokeLogProbFromLogits(cum_log_probs,
505	                            lp_logits_buf_,
506	                            input_ids,
507	                            input_lengths,
508	                            max_input_length,
509	                            batchxbeam,
510	                            vocab_size_,
511	                            vocab_size_padded_,
512	                            lp_logprob_buf_,
513	                            sizeof(float) * batchxbeam * max_input_length,
514	                            stream_,
515	                            true);
516	    sync_check_cuda_error();
517	}
